sql:
SELECT m.machine_id, m.machine_name, mr.maintenance_type
FROM pinball_machines m
JOIN maintenance_records mr ON m.machine_id = mr.machine_id;

SELECT year_of_production, COUNT(*) AS machine_count
FROM pinball_machines
GROUP BY year_of_production;

SELECT pm.machine_name, pm.model, pm.manufacturer, mr.maintenance_type
FROM pinball_machines pm
JOIN maintenance_records mr ON pm.machine_id = mr.machine_id;

SELECT pm.machine_name, pm.model, pm.manufacturer, pm.year_of_production, pm.location
FROM pinball_machines AS pm
JOIN performance_metrics AS pm_metrics ON pm.machine_id = pm_metrics.machine_id
WHERE pm_metrics.season_high = (
    SELECT MAX(season_high) FROM performance_metrics
) 
AND pm_metrics.season_plays = (
    SELECT MAX(season_plays) FROM performance_metrics
)
AND pm.machine_id IN (
    SELECT machine_id FROM maintenance_records
)
ORDER BY pm.machine_name ASC;

external_knowledge:
- Performance metrics for a pinball machine may include average score, high score, low score, and number of plays during a season; 
- Location details refer to the physical location where the machine is installed; 
- Installation and maintenance information includes the date of installation, last service date, and current operational status; 
- Technician details include name, contact number, certification level, email, years of experience, and specializations.

sql:
SELECT AVG(year_of_production) AS average_year_of_production
FROM pinball_machines
WHERE status = 'out of service';

external_knowledge:
- 'most in demand' refers to machines with more than 500 season plays; 
- 'seasoned technicians' implies experienced professionals with one or more specializations.
- The threshold of 500 season plays is an operational definition for 'heavy usage'.

sql:
SELECT machine_name, model
FROM pinball_machines
ORDER BY machine_name ASC;

SELECT pm.machine_name, pm.model, pm.manufacturer, pm.location, mr.maintenance_date
FROM pinball_machines pm
JOIN maintenance_records mr ON pm.machine_id = mr.machine_id;

external_knowledge:
- The term 'key performance metrics' refers to the average season score, highest season score, lowest season score, and total season games; 
- 'Maintenance histories' include total maintenance records and total technicians assisted; 
- 'Operational status' is categorized into active, maintenance, and out of service; 
- 'Service age' is calculated by subtracting the last service date from the current date in years.
